import React from 'react';

const entries = [
  {
    role: 'Freelance Web Developer',
    company: 'Self-employed',
    duration: '2024 – Present',
    description: 'Built and deployed personal and academic web projects using HTML, CSS, JavaScript, and React.',
    sym: '○',
    color: '#e87b7b',
  },
  {
    role: 'IT Intern (Placeholder)',
    company: 'Company Name Here',
    duration: 'Month Year – Month Year',
    description: 'Placeholder experience entry. Update this with your actual internship or work experience.',
    sym: '✕',
    color: '#7fc5e8',
  },
];

const Experience = () => (
  <section
    id="Experience"
    className="min-h-screen flex flex-col justify-center items-center px-5 py-24"
    style={{ background: 'var(--ps-navy, #0a0f2e)' }}
  >
    <h1 className="ps-title font-bold text-4xl text-white text-center mb-12">Experience</h1>

    <div className="w-full max-w-2xl flex flex-col gap-5">
      {entries.map((e, i) => (
        <div
          key={i}
          className="rounded-xl p-6 transition-transform duration-300 hover:-translate-y-1"
          style={{
            background: 'rgba(0,55,145,0.15)',
            border: `1px solid ${e.color}44`,
            borderLeft: `3px solid ${e.color}`,
          }}
        >
          <div className="flex items-center gap-3 mb-2">
            <span
              style={{
                display: 'inline-flex',
                alignItems: 'center',
                justifyContent: 'center',
                width: '28px',
                height: '28px',
                borderRadius: '50%',
                border: `1.5px solid ${e.color}`,
                color: e.color,
                fontSize: '13px',
                flexShrink: 0,
              }}
            >
              {e.sym}
            </span>
            <h3 className="font-bold text-base" style={{ color: e.color }}>{e.role}</h3>
          </div>
          <p className="italic text-sm mt-1" style={{ color: 'rgba(255,255,255,0.55)' }}>{e.company}</p>
          <p className="text-xs mt-1" style={{ color: 'rgba(255,255,255,0.4)' }}>{e.duration}</p>
          <p className="text-sm mt-3 leading-relaxed" style={{ color: 'rgba(255,255,255,0.75)' }}>{e.description}</p>
        </div>
      ))}
    </div>
  </section>
);

export default Experience;
